<template><div class="login-page lab-login"><section class="login-visual"><div class="visual-grid"></div><div class="visual-content"><div class="visual-brand"><el-icon><DataAnalysis/></el-icon><span>NEUSOFT SMART CARE</span></div><div class="visual-copy"><span class="eyebrow">LABORATORY WORKSTATION</span><h1>让每一份报告，<br/>成为诊疗的可靠依据</h1><p>检验申请统一流转、仪器结果智能审核、报告全程留痕，为临床诊断提供准确及时的数据支持。</p><div class="trust-row"><div><strong>精准</strong><span>结果审核</span></div><div><strong>实时</strong><span>报告同步</span></div><div><strong>全程</strong><span>质量追溯</span></div></div></div><div class="visual-foot"><span></span>云脑诊疗平台 · 医学检验中心</div></div></section><section class="login-panel"><div class="login-card"><span class="eyebrow">WELCOME BACK</span><h2>检验人员登录</h2><p>请输入工作账号，进入智慧检验科工作台</p><el-form ref="formRef" :model="form" :rules="rules" label-position="top" @keyup.enter="submit"><el-form-item label="工作账号" prop="username"><el-input v-model="form.username" size="large" :prefix-icon="User" placeholder="请输入检验科账号"/></el-form-item><el-form-item label="登录密码" prop="password"><el-input v-model="form.password" size="large" type="password" show-password :prefix-icon="Lock" placeholder="请输入登录密码"/></el-form-item><div class="login-options"><el-checkbox v-model="remember">记住账号</el-checkbox><span>内部系统 · 请勿共享账号</span></div><el-button type="primary" size="large" :loading="loading" class="login-btn" @click="submit">进入检验工作台 <el-icon><Right/></el-icon></el-button></el-form><div class="login-safe"><el-icon><Lock/></el-icon>JWT 安全认证 · 报告操作全程记录</div></div></section></div></template>
<script setup lang="ts">import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage,type FormInstance,type FormRules}from'element-plus';import{DataAnalysis,User,Lock,Right}from'@element-plus/icons-vue';import{useAuthStore}from'@/stores/auth';const router=useRouter(),auth=useAuthStore(),formRef=ref<FormInstance>(),loading=ref(false),remember=ref(true);const form=reactive({username:localStorage.getItem('lab_username')||'lab01',password:'123456'});const rules:FormRules={username:[{required:true,message:'请输入工作账号',trigger:'blur'}],password:[{required:true,message:'请输入登录密码',trigger:'blur'}]};const submit=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;loading.value=true;try{await auth.signIn(form.username,form.password);remember.value?localStorage.setItem('lab_username',form.username):localStorage.removeItem('lab_username');ElMessage.success('登录成功，欢迎回来');router.replace('/dashboard')}finally{loading.value=false}}</script>

